const express = require('express');
const http = require('http');
const { Server } = require('socket.io');
const cors = require('cors');
const { v4: uuidv4 } = require('uuid');
const db = require('./db');

const app = express();
const server = http.createServer(app);

const CORS_ORIGINS = ['http://localhost:5173', 'http://localhost:4173'];

const io = new Server(server, {
  cors: { origin: CORS_ORIGINS, methods: ['GET', 'POST', 'PATCH', 'DELETE'] }
});

app.use(cors({ origin: CORS_ORIGINS }));
app.use(express.json());

// ============ HELPERS ============

function createNotification(userId, roomId, type, message) {
  const id = uuidv4();
  const now = Date.now();
  db.prepare(
    'INSERT INTO notifications (id, user_id, room_id, type, message, is_read, created_at) VALUES (?, ?, ?, ?, ?, 0, ?)'
  ).run(id, userId, roomId, type, message, now);
  const notif = { id, user_id: userId, room_id: roomId, type, message, is_read: 0, created_at: now };
  io.to(`user_${userId}`).emit('notification', notif);
}

// ============ USERS ============

app.post('/api/users', (req, res) => {
  const { name, id } = req.body;
  if (!name || !name.trim()) return res.status(400).json({ error: 'Name is required' });

  const trimmedName = name.trim();

  if (id) {
    const existing = db.prepare('SELECT * FROM users WHERE id = ?').get(id);
    if (existing) {
      if (existing.name !== trimmedName) {
        db.prepare('UPDATE users SET name = ? WHERE id = ?').run(trimmedName, id);
        return res.json({ ...existing, name: trimmedName });
      }
      return res.json(existing);
    }
  }

  const userId = id || uuidv4();
  const now = Date.now();
  db.prepare('INSERT INTO users (id, name, created_at) VALUES (?, ?, ?)').run(userId, trimmedName, now);
  res.json({ id: userId, name: trimmedName, created_at: now });
});

// ============ ROOMS ============

app.post('/api/rooms', (req, res) => {
  const { title, creator_id } = req.body;
  if (!creator_id) return res.status(400).json({ error: 'creator_id required' });

  const roomId = uuidv4().replace(/-/g, '').slice(0, 10);
  const now = Date.now();
  const trimmedTitle = title ? title.trim() || null : null;

  db.prepare('INSERT INTO rooms (id, title, creator_id, is_locked, created_at) VALUES (?, ?, ?, 0, ?)')
    .run(roomId, trimmedTitle, creator_id, now);

  res.json({ id: roomId, title: trimmedTitle, creator_id, is_locked: 0, created_at: now });
});

app.get('/api/rooms/:id', (req, res) => {
  const room = db.prepare('SELECT * FROM rooms WHERE id = ?').get(req.params.id);
  if (!room) return res.status(404).json({ error: 'Room not found' });
  res.json(room);
});

app.patch('/api/rooms/:id', (req, res) => {
  const { is_locked, user_id } = req.body;
  const room = db.prepare('SELECT * FROM rooms WHERE id = ?').get(req.params.id);
  if (!room) return res.status(404).json({ error: 'Room not found' });
  if (room.creator_id !== user_id) return res.status(403).json({ error: 'Only the room creator can do this' });

  if (is_locked !== undefined) {
    db.prepare('UPDATE rooms SET is_locked = ? WHERE id = ?').run(is_locked ? 1 : 0, req.params.id);
  }

  const updated = db.prepare('SELECT * FROM rooms WHERE id = ?').get(req.params.id);
  io.to(req.params.id).emit('room_updated', updated);
  res.json(updated);
});

// ============ CONTRIBUTIONS ============

app.get('/api/rooms/:id/contributions', (req, res) => {
  const contributions = db.prepare(`
    SELECT c.*,
      COALESCE((
        SELECT json_group_array(json_object('id', r.id, 'emoji', r.emoji, 'user_id', r.user_id))
        FROM reactions r WHERE r.contribution_id = c.id
      ), '[]') as reactions_json
    FROM contributions c
    WHERE c.room_id = ?
    ORDER BY c.created_at ASC
  `).all(req.params.id);

  const result = contributions.map(({ reactions_json, ...c }) => ({
    ...c,
    reactions: JSON.parse(reactions_json)
  }));

  res.json(result);
});

app.post('/api/rooms/:id/contributions', (req, res) => {
  const room = db.prepare('SELECT * FROM rooms WHERE id = ?').get(req.params.id);
  if (!room) return res.status(404).json({ error: 'Room not found' });
  if (room.is_locked) return res.status(403).json({ error: 'This room is locked' });

  const { author_id, author_name, content, parent_id } = req.body;
  if (!content?.trim() || !author_id || !author_name) {
    return res.status(400).json({ error: 'author_id, author_name, and content are required' });
  }

  const id = uuidv4();
  const now = Date.now();
  const trimmedContent = content.trim();

  db.prepare(
    'INSERT INTO contributions (id, room_id, author_id, author_name, content, parent_id, created_at) VALUES (?, ?, ?, ?, ?, ?, ?)'
  ).run(id, req.params.id, author_id, author_name, trimmedContent, parent_id || null, now);

  const contribution = {
    id, room_id: req.params.id, author_id, author_name,
    content: trimmedContent, parent_id: parent_id || null, created_at: now, reactions: []
  };

  io.to(req.params.id).emit('new_contribution', contribution);

  // Notify parent author if this is a reply
  if (parent_id) {
    const parent = db.prepare('SELECT * FROM contributions WHERE id = ?').get(parent_id);
    if (parent && parent.author_id !== author_id) {
      createNotification(parent.author_id, req.params.id, 'reply', `${author_name} replied to your contribution`);
    }
  } else {
    // Notify all unique previous contributors
    const roomUsers = db.prepare(
      'SELECT DISTINCT author_id FROM contributions WHERE room_id = ? AND author_id != ? AND id != ?'
    ).all(req.params.id, author_id, id);

    roomUsers.forEach(u => {
      createNotification(u.author_id, req.params.id, 'new_contribution', `${author_name} added a new contribution`);
    });
  }

  res.json(contribution);
});

app.delete('/api/contributions/:id', (req, res) => {
  const { user_id } = req.body;
  const contribution = db.prepare('SELECT * FROM contributions WHERE id = ?').get(req.params.id);
  if (!contribution) return res.status(404).json({ error: 'Not found' });

  const room = db.prepare('SELECT * FROM rooms WHERE id = ?').get(contribution.room_id);
  if (room.creator_id !== user_id && contribution.author_id !== user_id) {
    return res.status(403).json({ error: 'Not authorized' });
  }

  db.prepare('DELETE FROM reactions WHERE contribution_id = ?').run(req.params.id);
  db.prepare('DELETE FROM comments WHERE contribution_id = ?').run(req.params.id);
  db.prepare('DELETE FROM contributions WHERE id = ?').run(req.params.id);

  io.to(contribution.room_id).emit('contribution_deleted', { id: req.params.id });
  res.json({ success: true });
});

// ============ COMMENTS ============

app.get('/api/contributions/:id/comments', (req, res) => {
  const comments = db.prepare(
    'SELECT * FROM comments WHERE contribution_id = ? ORDER BY created_at ASC'
  ).all(req.params.id);
  res.json(comments);
});

app.post('/api/contributions/:id/comments', (req, res) => {
  const { author_id, author_name, content, parent_id } = req.body;
  if (!content?.trim() || !author_id || !author_name) {
    return res.status(400).json({ error: 'Missing required fields' });
  }

  const contribution = db.prepare('SELECT * FROM contributions WHERE id = ?').get(req.params.id);
  if (!contribution) return res.status(404).json({ error: 'Contribution not found' });

  const id = uuidv4();
  const now = Date.now();
  const trimmedContent = content.trim();

  db.prepare(
    'INSERT INTO comments (id, contribution_id, author_id, author_name, content, parent_id, created_at) VALUES (?, ?, ?, ?, ?, ?, ?)'
  ).run(id, req.params.id, author_id, author_name, trimmedContent, parent_id || null, now);

  const comment = {
    id, contribution_id: req.params.id, author_id, author_name,
    content: trimmedContent, parent_id: parent_id || null, created_at: now
  };

  io.to(contribution.room_id).emit('new_comment', { contribution_id: req.params.id, comment });

  // Notify contribution author
  if (contribution.author_id !== author_id) {
    createNotification(contribution.author_id, contribution.room_id, 'comment', `${author_name} commented on your contribution`);
  }

  // Notify parent comment author if it's a reply
  if (parent_id) {
    const parentComment = db.prepare('SELECT * FROM comments WHERE id = ?').get(parent_id);
    if (parentComment && parentComment.author_id !== author_id && parentComment.author_id !== contribution.author_id) {
      createNotification(parentComment.author_id, contribution.room_id, 'reply', `${author_name} replied to your comment`);
    }
  }

  res.json(comment);
});

// ============ REACTIONS ============

const ALLOWED_EMOJIS = ['👍', '❤️', '😄', '🔥', '✨'];

app.post('/api/contributions/:id/reactions', (req, res) => {
  const { user_id, emoji } = req.body;
  if (!user_id || !emoji) return res.status(400).json({ error: 'Missing fields' });
  if (!ALLOWED_EMOJIS.includes(emoji)) return res.status(400).json({ error: 'Invalid emoji' });

  const contribution = db.prepare('SELECT * FROM contributions WHERE id = ?').get(req.params.id);
  if (!contribution) return res.status(404).json({ error: 'Not found' });

  const existing = db.prepare(
    'SELECT * FROM reactions WHERE contribution_id = ? AND user_id = ? AND emoji = ?'
  ).get(req.params.id, user_id, emoji);

  if (existing) {
    db.prepare('DELETE FROM reactions WHERE id = ?').run(existing.id);
  } else {
    db.prepare(
      'INSERT INTO reactions (id, contribution_id, user_id, emoji, created_at) VALUES (?, ?, ?, ?, ?)'
    ).run(uuidv4(), req.params.id, user_id, emoji, Date.now());
  }

  const reactions = db.prepare('SELECT * FROM reactions WHERE contribution_id = ?').all(req.params.id);
  io.to(contribution.room_id).emit('reactions_updated', { contribution_id: req.params.id, reactions });
  res.json(reactions);
});

// ============ NOTIFICATIONS ============

app.get('/api/notifications', (req, res) => {
  const { user_id } = req.query;
  if (!user_id) return res.status(400).json({ error: 'user_id required' });
  const notifications = db.prepare(
    'SELECT * FROM notifications WHERE user_id = ? ORDER BY created_at DESC LIMIT 50'
  ).all(user_id);
  res.json(notifications);
});

// Must come before /:id route
app.patch('/api/notifications/read-all', (req, res) => {
  const { user_id } = req.body;
  if (!user_id) return res.status(400).json({ error: 'user_id required' });
  db.prepare('UPDATE notifications SET is_read = 1 WHERE user_id = ?').run(user_id);
  res.json({ success: true });
});

app.patch('/api/notifications/:id/read', (req, res) => {
  db.prepare('UPDATE notifications SET is_read = 1 WHERE id = ?').run(req.params.id);
  res.json({ success: true });
});

// ============ SOCKET.IO ============

io.on('connection', (socket) => {
  socket.on('join_room', (roomId) => socket.join(roomId));
  socket.on('join_user', (userId) => socket.join(`user_${userId}`));
  socket.on('leave_room', (roomId) => socket.leave(roomId));
  socket.on('typing', ({ roomId, userName }) => {
    socket.to(roomId).emit('user_typing', { userName });
  });
});

// ============ START ============

const PORT = process.env.PORT || 3001;
server.listen(PORT, () => {
  console.log(`Server listening on http://localhost:${PORT}`);
});

