      }),
      fetch(`/api/rooms/${roomId}/contributions`).then(r => r.json())
    ])
      .then(([roomData, contribData]) => {
        setRoom(roomData);
        setContributions(contribData);
      })
      .catch(err => setError(err.message))
      .finally(() => setLoading(false));
  }, [roomId]);

